function solve(nums) {
    const n = nums.length;
    if (n <= 1) {
        return new Array(n).fill(0);
    }

    const answer = new Array(n).fill(0);

    for (let i = 0; i < n; i++) {
        const currentParity = nums[i] % 2; // 0 for even, 1 for odd
        let score = 0;

        // Count odd and even numbers to the right of i
        let rightOddCount = 0;
        let rightEvenCount = 0;

        for (let j = i + 1; j < n; j++) {
            const nextParity = nums[j] % 2;
            if (nextParity === 1) { // Odd
                rightOddCount++;
            } else { // Even
                rightEvenCount++;
            }
        }

        // Calculate the score for index i
        if (currentParity === 1) { // nums[i] is odd
            // Score is the count of even numbers to the right
            score = rightEvenCount;
        } else { // nums[i] is even
